#include <limits>
#include <atomic>
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/internal/get_time.h"
#include "common/graph.h"
#include "BFS.h"

using namespace std;

parlay::sequence<vertexId> BFS(vertexId start, const Graph &G, bool verbose = false) {
  parlay::internal::timer t("BFS", verbose);
  size_t n = G.numVertices();
  size_t m = G.numEdges();

  // Initialize parent array
  auto parent = parlay::sequence<std::atomic<vertexId>>::from_function(n, [](size_t) {
    return -1;
  });
  parent[start] = start;

  // Current and next frontiers
  parlay::sequence<vertexId> frontier(1, start);
  parlay::sequence<vertexId> next_frontier;

  // Dense representation for bottom-up
  auto visited = parlay::sequence<std::atomic<bool>>::from_function(n, [](size_t) {
    return false;
  });
  visited[start] = true;

  // Statistics for direction optimization
  size_t edges_to_check = 0;
  size_t scout_count = 0;
  size_t awake_count = 1;
  size_t old_awake_count = 0;

  // Thresholds for switching between top-down and bottom-up
  const size_t alpha = 15;  // edges_to_check/m threshold
  const size_t beta = 18;   // frontier_size/n threshold

  bool use_dense = false;

  t.next("init");

  while (!frontier.empty()) {
    old_awake_count = awake_count;

    // Estimate edges to check for top-down
    if (!use_dense) {
      edges_to_check = parlay::reduce(
        parlay::delayed_map(frontier, [&](vertexId v) {
          return (size_t)G[v].degree;
        })
      );
    }

    // Decide direction
    bool should_switch_to_dense = 
      (edges_to_check > m / alpha) && 
      (frontier.size() > n / beta);

    bool should_switch_to_sparse = 
      use_dense && (frontier.size() < n / beta);

    if (should_switch_to_dense && !use_dense) {
      use_dense = true;
      if (verbose) cout << "Switching to bottom-up" << endl;
    } else if (should_switch_to_sparse && use_dense) {
      use_dense = false;
      if (verbose) cout << "Switching to top-down" << endl;
    }

    if (!use_dense) {
      // Top-down traversal
      size_t frontier_size = frontier.size();

      // Pre-allocate space for next frontier (overestimate)
      size_t estimated_size = min(edges_to_check, n);
      next_frontier = parlay::sequence<vertexId>::uninitialized(estimated_size);
      auto next_frontier_flags = parlay::sequence<bool>::uninitialized(estimated_size);
      std::atomic<size_t> next_frontier_size(0);

      // Process frontier in parallel
      parlay::parallel_for(0, frontier_size, [&](size_t i) {
        vertexId u = frontier[i];
        auto vertex_u = G[u];
        vertexId degree = vertex_u.degree;
        const vertexId* neighbors = vertex_u.Neighbors;

        // Local buffer to reduce atomic operations
        constexpr size_t local_buf_size = 64;
        vertexId local_buf[local_buf_size];
        size_t local_count = 0;

        for (vertexId j = 0; j < degree; j++) {
          vertexId v = neighbors[j];
          vertexId expected = -1;
          if (parent[v].compare_exchange_strong(expected, u)) {
            visited[v] = true;
            local_buf[local_count++] = v;

            if (local_count == local_buf_size) {
              size_t idx = next_frontier_size.fetch_add(local_count);
              for (size_t k = 0; k < local_count; k++) {
                next_frontier[idx + k] = local_buf[k];
                next_frontier_flags[idx + k] = true;
              }
              local_count = 0;
            }
          }
        }

        // Flush remaining vertices
        if (local_count > 0) {
          size_t idx = next_frontier_size.fetch_add(local_count);
          for (size_t k = 0; k < local_count; k++) {
            next_frontier[idx + k] = local_buf[k];
            next_frontier_flags[idx + k] = true;
          }
        }
      }, 1);

      // Compact the next frontier
      size_t actual_size = next_frontier_size.load();
      next_frontier.resize(actual_size);
      frontier = std::move(next_frontier);
      awake_count = frontier.size();

    } else {
      // Bottom-up traversal
      auto next_visited = parlay::sequence<std::atomic<bool>>::from_function(n, [](size_t) {
        return false;
      });
      std::atomic<size_t> awake_count_atomic(0);

      parlay::parallel_for(0, n, [&](vertexId v) {
        if (!visited[v].load(std::memory_order_relaxed)) {
          auto vertex_v = G[v];
          vertexId degree = vertex_v.degree;
          const vertexId* neighbors = vertex_v.Neighbors;

          for (vertexId j = 0; j < degree; j++) {
            vertexId u = neighbors[j];
            if (visited[u].load(std::memory_order_relaxed) && 
                !next_visited[u].load(std::memory_order_relaxed)) {
              parent[v] = u;
              visited[v] = true;
              next_visited[v] = true;
              awake_count_atomic.fetch_add(1, std::memory_order_relaxed);
              break;
            }
          }
        }
      }, 512);

      awake_count = awake_count_atomic.load();

      // Convert back to sparse if needed for next iteration
      if (awake_count < n / beta) {
        frontier = parlay::pack_index<vertexId>(
          parlay::tabulate(n, [&](size_t i) {
            return next_visited[i].load();
          })
        );
      }
    }

    if (verbose) {
      cout << "Round: frontier=" << awake_count 
           << ", explored=" << awake_count - old_awake_count << endl;
    }
    t.next("round");
  }

  // Convert atomic parent array to regular sequence
  return parlay::map(parent, [](auto const &x) -> vertexId {
    return x.load();
  });
}
